+                    consecutive_budget_exhaustions =
+                        consecutive_budget_exhaustions.saturating_add(1);
+                    let backoff_ms = match consecutive_budget_exhaustions {
+                        1 => 1,
+                        2 => 5,
+                        _ => 25,
